--
-- TOC entry 423 (class 1259 OID 21714)
-- Name: v_40ft_container_validation; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_40ft_container_validation WITH (security_invoker='on') AS
 SELECT id,
    number AS container_number,
    size,
    location,
    ("substring"(location, 'S0*(\d+)'::text))::integer AS stack_number,
        CASE
            WHEN (("substring"(location, 'S0*(\d+)'::text))::integer = ANY (ARRAY[4, 8, 12, 16, 20, 24, 28, 34, 38, 42, 46, 50, 54, 62, 66, 70, 74, 78, 82, 86, 90, 94, 98])) THEN 'VALID - Virtual Stack'::text
            WHEN ((("substring"(location, 'S0*(\d+)'::text))::integer % 2) = 1) THEN 'INVALID - Odd Physical Stack'::text
            ELSE 'INVALID - Not a recognized virtual stack'::text
        END AS validation_status,
    client_code,
    status,
    created_at,
    updated_at
   FROM public.containers c
  WHERE (((size = '40ft'::text) OR (size = '40feet'::text)) AND (location IS NOT NULL))
  ORDER BY
        CASE
            WHEN (("substring"(location, 'S0*(\d+)'::text))::integer = ANY (ARRAY[4, 8, 12, 16, 20, 24, 28, 34, 38, 42, 46, 50, 54, 62, 66, 70, 74, 78, 82, 86, 90, 94, 98])) THEN 'VALID - Virtual Stack'::text
            WHEN ((("substring"(location, 'S0*(\d+)'::text))::integer % 2) = 1) THEN 'INVALID - Odd Physical Stack'::text
            ELSE 'INVALID - Not a recognized virtual stack'::text
        END DESC, created_at DESC;


ALTER VIEW public.v_40ft_container_validation OWNER TO postgres;

--
-- TOC entry 5786 (class 0 OID 0)
-- Dependencies: 423
-- Name: VIEW v_40ft_container_validation; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.v_40ft_container_validation IS 'Monitoring view for 40ft container placements. Shows validation status for each 40ft container location.';


--
-- TOC entry 437 (class 1259 OID 47990)
-- Name: v_gate_in_operations_full; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_gate_in_operations_full AS
 SELECT gio.id,
    gio.container_id,
    gio.container_number,
    gio.client_code,
    gio.client_name,
    gio.container_type,
    gio.container_size,
    gio.status,
    gio.operator_id,
    gio.operator_name,
    gio.yard_id,
    gio.created_at,
    gio.completed_at,
    gio.entry_date,
    gio.entry_time,
    gio.classification,
    gio.container_number_confirmed,
    gio.second_container_number,
    gio.second_container_number_confirmed,
    gio.operation_status,
    gio.updated_at,
    gio.updated_by,
    gio.full_empty,
    gio.container_quantity,
    gio.transaction_type,
    gied.edi_message_id,
    gied.edi_client_name,
    gied.edi_client_code,
    gied.edi_gate_in_transmitted,
    gied.edi_transmission_date,
    gied.edi_log_id,
    gied.edi_error_message,
    gti.transport_company,
    gti.driver_name,
    gti.driver_phone,
    gti.vehicle_number,
    gti.truck_arrival_date,
    gti.truck_arrival_time,
    gti.booking_reference AS transport_booking_reference,
    gti.equipment_reference,
    gda.damage_reported,
    gda.damage_description,
    gda.damage_type,
    gda.damage_assessment,
    gda.damage_assessed_by,
    gda.damage_assessed_at,
    gda.damage_assessment_stage,
    gda.is_buffer_assignment,
    gda.assigned_stack,
    gda.assigned_location
   FROM (((public.gate_in_operations gio
     LEFT JOIN public.gate_in_edi_details gied ON ((gio.id = gied.gate_in_operation_id)))
     LEFT JOIN public.gate_in_transport_info gti ON ((gio.id = gti.gate_in_operation_id)))
     LEFT JOIN public.gate_in_damage_assessments gda ON ((gio.id = gda.gate_in_operation_id)));


ALTER VIEW public.v_gate_in_operations_full OWNER TO postgres;

